module top_module(input R, S, D, C, output reg RF, output RI);assign RI = ~RF;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge C or posedge dbg_halt)
  begin
    if (!R)
	 begin
	   RF <= 1'b0;
	 end
	 else if (!S)
	 begin
	   RF <= D;
	 end
	 else
	 begin
	   RF <= RF;
	 end

  end

endmodule
